INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1fa7cd8d-1bdb-4492-97e7-6ede9aa4221c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm Image Security — Digest Pinning, Non-Root Contexts, and Distroless Defaults$escape$,
  $escape$Mutable tags like `latest` are a supply-chain liability. Pin images by digest in your chart's `values.yaml` so every `helm upgrade` is reproducible and auditable. In your Deployment template, prefer `{{ .Values.image.repository }}@{{ .Values.image.digest }}` over tag interpolation.

For non-root enforcement, set `securityContext` defaults directly in the chart template — don't leave it to the operator. `runAsNonRoot: true`, `runAsUser: 65534` (nobody), and `readOnlyRootFilesystem: true` should be chart-level defaults, overridable only via explicit values.

Distroless images (e.g. `gcr.io/distroless/static-debian12`) eliminate the shell attack surface entirely — pair them with `allowPrivilegeEscalation: false` and drop all capabilities via `capabilities.drop: [ALL]`.

For CVE scanning in CI, use a Helm pre-upgrade hook Job that runs Trivy against the resolved image before rollout proceeds. If the Job fails, Helm aborts the release — no manual gate needed. Set `helm.sh/hook-delete-policy: before-hook-creation` to keep the namespace clean across upgrades.$escape$,
  $escape$# values.yaml
image:
  repository: gcr.io/distroless/static-debian12
  digest: sha256:a1b2c3d4e5f6...  # no mutable tag

securityContext:
  runAsNonRoot: true
  runAsUser: 65534
  readOnlyRootFilesystem: true
  allowPrivilegeEscalation: false
  capabilities:
    drop: ["ALL"]

# templates/pre-upgrade-scan.yaml
apiVersion: batch/v1
kind: Job
metadata:
  name: {{ include "mychart.fullname" . }}-cve-scan
  annotations:
    helm.sh/hook: pre-upgrade
    helm.sh/hook-weight: "-5"
    helm.sh/hook-delete-policy: before-hook-creation
spec:
  template:
    spec:
      restartPolicy: Never
      containers:
        - name: trivy
          image: aquasec/trivy:latest
          args:
            - image
            - --exit-code=1
            - --severity=CRITICAL
            - "{{ .Values.image.repository }}@{{ .Values.image.digest }}"$escape$,
  $escape$bash$escape$,
