INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a7124679-6d06-41fe-81c8-c2f20e82a540',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm — Controlling Pod Lifecycle and Deployment Strategies with values.yaml$escape$,
  $escape$Helm doesn't manage ReplicaSets or Deployments directly — it templates Kubernetes manifests, so your deployment strategy lives in `values.yaml` and gets stamped into the `spec.strategy` block of a `Deployment` resource. The two critical strategies are `RollingUpdate` (default) and `Recreate`. With `RollingUpdate`, Helm-rendered charts respect `maxSurge` and `maxUnavailable` to control how many pods are cycled simultaneously — misconfiguring these causes downtime during `helm upgrade`. Set `maxSurge: 1` and `maxUnavailable: 0` for zero-downtime deploys.

Helm's `--atomic` flag couples lifecycle to the upgrade: if the new ReplicaSet's pods don't reach `Ready` within `--timeout`, Helm auto-rolls back. Pod readiness is gated by `readinessProbe` — if your chart omits this, `--atomic` has nothing to wait on and upgrades appear to succeed when pods are still crashing. Always define `livenessProbe` and `readinessProbe` in your chart templates. Use `helm rollback <release> <revision>` to revert to any prior Helm-managed Deployment state tracked in the release history.$escape$,
  $escape$# values.yaml
replicaCount: 3

strategy:
  type: RollingUpdate
  rollingUpdate:
    maxSurge: 1
    maxUnavailable: 0

readinessProbe:
  httpGet:
    path: /healthz
    port: 8080
  initialDelaySeconds: 5
  periodSeconds: 10

livenessProbe:
  httpGet:
    path: /healthz
    port: 8080
  initialDelaySeconds: 15
  periodSeconds: 20

# Deploy with atomic rollback on failure
# helm upgrade --install my-app ./chart --atomic --timeout 3m$escape$,
  $escape$bash$escape$,
