INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af605fb9-dc3a-4702-a82a-52148ccc5f20',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm Service Types — ClusterIP vs NodePort vs LoadBalancer and Cluster DNS$escape$,
  $escape$When you define a Service in a Helm chart, the `service.type` value in `values.yaml` dictates reachability. `ClusterIP` (default) exposes the Service only inside the cluster — other Pods reach it via DNS at `<service-name>.<namespace>.svc.cluster.local`. This is the right default for internal microservices; never expose internals with a broader type. `NodePort` binds a port (30000–32767) on every Node's IP, useful for dev clusters without a cloud LB — but it's fragile in production. `LoadBalancer` provisions a cloud load balancer (AWS ALB, Azure LB) automatically; pair it with `service.annotations` in your values to pass cloud-specific config (e.g. `service.beta.kubernetes.io/aws-load-balancer-type`). In Helm charts, template your Service type cleanly: gate `nodePort` and `loadBalancerIP` fields with conditionals so they only render when relevant. Cluster DNS is automatic — once deployed, `helm install myapp ./chart -n payments` makes `myapp-payments.payments.svc.cluster.local` resolvable immediately. Use `ClusterIP` by default; override via `--set service.type=LoadBalancer` at install time for environment-specific promotion.$escape$,
  $escape$# values.yaml
service:
  type: ClusterIP  # override per env: NodePort | LoadBalancer
  port: 8080
  annotations: {}

# templates/service.yaml
apiVersion: v1
kind: Service
metadata:
  name: {{ include "mychart.fullname" . }}
  annotations: {{ toYaml .Values.service.annotations | nindent 4 }}
spec:
  type: {{ .Values.service.type }}
  ports:
    - port: {{ .Values.service.port }}
      targetPort: http
      {{- if eq .Values.service.type "NodePort" }}
      nodePort: 30080
      {{- end }}
  selector:
    {{- include "mychart.selectorLabels" . | nindent 4 }}$escape$,
  $escape$bash$escape$,
