INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ce26832e-080c-44c9-acd2-84d4dd5eaa7d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm ConfigMaps & Secrets — Externalizing Config and Encrypting at Rest$escape$,
  $escape$Helm separates config from code via `values.yaml`, but the real power comes from templating ConfigMaps and Secrets directly from those values. Define your app config in `values.yaml`, then render it into a ConfigMap using `{{ .Values.config | toYaml | indent 4 }}`. For Secrets, base64 encoding is automatic when you use the `Secret` kind — Helm's `b64enc` function handles encoding inline: `{{ .Values.db.password | b64enc | quote }}`.

For encryption at rest, the standard tool is `helm-secrets` backed by SOPS (Secrets OPerationS). Encrypt a values file with `helm secrets enc secrets.yaml`, committing the ciphertext safely to Git. At deploy time, `helm secrets upgrade` decrypts on the fly using a KMS key (AWS KMS, GCP KMS, or Azure Key Vault) — the plaintext never touches disk. Alternatively, use the `secrets://` driver with the vals plugin for dynamic resolution at render time. Avoid committing raw `Secret` manifests or unencrypted values files — treat any file referenced by `-f` as a potential leak surface.$escape$,
  $escape$# values.yaml
db:
  host: postgres.internal
  password: ENC[AES256_GCM,data:abc123==,type:str]

# templates/secret.yaml
apiVersion: v1
kind: Secret
metadata:
  name: {{ include "myapp.fullname" . }}-db
type: Opaque
data:
  password: {{ .Values.db.password | b64enc | quote }}

# Encrypt and deploy
helm secrets enc values/secrets.yaml
helm secrets upgrade myapp ./chart -f values/secrets.yaml$escape$,
  $escape$bash$escape$,
