INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0905c1cf-26c1-47ea-bc7b-3fc3f8b851ed',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm — Mastering Values Merging and Template Overrides Across Environments$escape$,
  $escape$Helm resolves values through a deterministic merge chain: chart defaults (values.yaml) < umbrella chart < -f flag files (left to right) < --set flags. Later sources win. This means you can layer environment configs cleanly: a base values.yaml defines production-safe defaults, then values.staging.yaml overrides only what differs.

Templates live in templates/ and use Go text/template with Helm's Sprig extensions. The .Values object exposes your merged values tree; .Release.Name and .Chart.Name are built-in objects injecting release metadata. Use named templates in _helpers.tpl with {{- define "app.labels" -}} blocks and invoke them via {{- include "app.labels" . | nindent 4 }}—prefer include over template because include captures output for pipeline chaining.

Release state is stored in Kubernetes Secrets (default) as base64-encoded gzipped JSON. helm history <release> surfaces the full revision log; helm rollback <release> <revision> atomically restores the prior manifest set. Use helm diff upgrade (from the helm-diff plugin) before every apply in CI to catch unintended drift before it hits the cluster.$escape$,
  $escape$# Layer environment-specific overrides at deploy time
helm upgrade --install my-app ./charts/my-app \
  -f values.yaml \
  -f values.staging.yaml \
  --set image.tag=$(git rev-parse --short HEAD) \
  --namespace staging --create-namespace

# _helpers.tpl — reusable label block
{{- define "my-app.labels" -}}
app.kubernetes.io/name: {{ include "my-app.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}

# Inspect release history and roll back if needed
helm history my-app --namespace staging
helm rollback my-app 3 --namespace staging$escape$,
  $escape$bash$escape$,
