INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ee5bcaed-be47-4662-8127-4dd06378d4d3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm + Kubernetes Autoscaling — HPA, VPA, and KEDA in One Chart$escape$,
  $escape$Helm charts ship autoscaling primitives out of the box, but wiring HPA, VPA, and KEDA together requires deliberate values design. Most official charts expose a `autoscaling.enabled` toggle that renders an HPA manifest — but VPA and KEDA require separate CRD-backed resources you must template yourself.

For HPA, the standard pattern uses `spec.metrics` with `ContainerResource` type (Kubernetes 1.27+) rather than the legacy `Resource` type, giving per-container granularity. Drop it under `templates/hpa.yaml` and gate it with `{{- if .Values.autoscaling.hpa.enabled }}`.

For KEDA, install the `kedacore/keda` Helm chart as a dependency in `Chart.yaml`, then define a `ScaledObject` template referencing your Deployment. KEDA's `ScaledObject` replaces the HPA entirely — never run both simultaneously on the same workload, or you'll get conflicting replica counts.

VPA is advisory-only by default (`updateMode: Off`) — useful for right-sizing `requests` without disrupting pods. Add it as a separate template and enable independently. Use `helm template` locally to validate all three render correctly before `helm upgrade --install`.$escape$,
  $escape$# Chart.yaml — KEDA as a dependency
dependencies:
  - name: keda
    version: "2.14.0"
    repository: "https://kedacore.github.io/charts"
    condition: keda.enabled

---
# templates/scaledobject.yaml
{{- if .Values.autoscaling.keda.enabled }}
apiVersion: keda.sh/v1alpha1
kind: ScaledObject
metadata:
  name: {{ include "mychart.fullname" . }}
spec:
  scaleTargetRef:
    name: {{ include "mychart.fullname" . }}
  minReplicaCount: {{ .Values.autoscaling.keda.minReplicas }}
  maxReplicaCount: {{ .Values.autoscaling.keda.maxReplicas }}
  triggers:
    - type: {{ .Values.autoscaling.keda.triggerType }}
      metadata: {{- toYaml .Values.autoscaling.keda.triggerMetadata | nindent 8 }}
{{- end }}$escape$,
  $escape$bash$escape$,
