INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eb76e0ea-656a-4967-a9ae-dc3d0050c023',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm & Kubernetes RBAC — Scoping Releases to Namespaces with Least Privilege$escape$,
  $escape$Helm respects Kubernetes RBAC boundaries entirely — it operates using the credentials of whoever runs `helm install`. In multi-tenant clusters, this means you must scope each tenant's service account to its own namespace and bind only the roles it needs.

Create a dedicated ServiceAccount per tenant, then bind a Role (not ClusterRole) limited to the resources Helm actually touches: Secrets (for release state), ConfigMaps, Deployments, and Services. Helm 3 stores release metadata as Secrets in the target namespace by default (`--storage-driver=secret`), so the service account needs `get/list/create/update/delete` on Secrets in that namespace only — not cluster-wide.

Pass the scoped kubeconfig or service account token via `KUBECONFIG` or `helm --kube-context`. Use `helm install --namespace tenant-a --create-namespace` to keep releases isolated. Validate the blast radius with `helm list --all-namespaces` to confirm no cross-namespace leakage. For CI pipelines, generate short-lived tokens with `kubectl create token` rather than static kubeconfig files.$escape$,
  $escape$# rbac.yaml — scoped Role + binding for a Helm service account
apiVersion: v1
kind: ServiceAccount
metadata:
  name: helm-tenant-a
  namespace: tenant-a
---
apiVersion: rbac.authorization.k8s.io/v1
kind: Role
metadata:
  name: helm-deployer
  namespace: tenant-a
rules:
  - apiGroups: [""]
    resources: ["secrets", "configmaps", "services"]
    verbs: ["get", "list", "create", "update", "delete"]
  - apiGroups: ["apps"]
    resources: ["deployments"]
    verbs: ["get", "list", "create", "update", "delete"]
---
apiVersion: rbac.authorization.k8s.io/v1
kind: RoleBinding
metadata:
  name: helm-deployer-binding
  namespace: tenant-a
subjects:
  - kind: ServiceAccount
    name: helm-tenant-a
    namespace: tenant-a
roleRef:
  kind: Role
  name: helm-deployer
  apiGroup: rbac.authorization.k8s.io$escape$,
  $escape$bash$escape$,
