INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7ac5956c-af11-4114-88cf-828300a92ef4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Helm Network Policies — Locking Down Pod-to-Pod Traffic Without Hardcoding IPs$escape$,
  $escape$Helm's `.Values` system lets you template NetworkPolicy manifests so the same chart works across namespaces without manual IP edits. The key is using `podSelector` with `matchLabels` that mirror your chart's own label convention — typically `app.kubernetes.io/name: {{ include "mychart.name" . }}`. For ingress controllers, you need a separate `namespaceSelector` rule targeting the namespace where your ingress controller lives (e.g., `ingress-nginx`). Without it, your controller can't reach pods even if external traffic hits the Service. Pair `podSelector: {}` with `namespaceSelector` to allow cross-namespace traffic only from that controller namespace. Use `helm template` locally to render the policy and verify selectors match actual pod labels before applying — label mismatches silently drop traffic. Gate the entire NetworkPolicy block behind a `Values.networkPolicy.enabled` flag so teams can opt out in dev clusters where CNI plugins don't enforce policies. This keeps your chart portable across environments without forking templates.$escape$,
  $escape${{- if .Values.networkPolicy.enabled }}
apiVersion: networking.k8s.io/v1
kind: NetworkPolicy
metadata:
  name: {{ include "mychart.fullname" . }}
spec:
  podSelector:
    matchLabels:
      {{- include "mychart.selectorLabels" . | nindent 6 }}
  policyTypes: [Ingress]
  ingress:
    - from:
        - namespaceSelector:
            matchLabels:
              kubernetes.io/metadata.name: ingress-nginx
          podSelector:
            matchLabels:
              app.kubernetes.io/name: ingress-nginx
{{- end }}$escape$,
  $escape$bash$escape$,
